//go:build ignore

// Command gen_token_tables generates token_tables_gen.go from the master token
// list below: the SWAR keyword matcher (getSpecialToken), tokenToString,
// isImportant, and the special-character lookup. Edit the lists here and run
// `go generate ./...` — do not hand-edit the generated file.
package main

import (
	"fmt"
	"go/format"
	"log"
	"os"
	"strconv"
	"strings"
)

// keywordToken is a token matched from one or more case-insensitive keywords.
type keywordToken struct {
	Const    string   // Token constant name
	Debug    string   // tokenToString output
	Keywords []string // keywords that map to this token (uppercase)
	Critical bool     // reported by isImportant
}

// charToken is a token matched from a single byte.
type charToken struct {
	Const string
	Char  byte
}

var keywordTokens = []keywordToken{
	{"Month", "MTH", []string{"JAN", "FEB", "MAR", "APR", "MAY", "JUN", "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"}, false},
	{"Day", "DAY", []string{"MON", "TUE", "WED", "THU", "FRI", "SAT", "SUN"}, false},
	{"Apm", "PM", []string{"AM", "PM"}, false},
	{"Zone", "ZONE", []string{
		"Z",
		"UTC", "GMT", "EST", "EDT", "CST", "CDT", "MST", "MDT", "PST", "PDT",
		"JST", "KST", "IST", "MSK", "CET", "BST", "HST", "HDT", "NST", "NDT",
		"CEST", "NZST", "NZDT", "ACST", "ACDT", "AEST", "AEDT", "AWST", "AWDT",
		"AKST", "AKDT", "CHST", "CHDT",
	}, false},
	{"T", "T", []string{"T"}, false},
	{"Warn", "WARN", []string{"WARN", "WARNING"}, true},
	{"Fatal", "FATAL", []string{"FATAL"}, true},
	{"Error", "ERROR", []string{"ERROR"}, true},
	{"Panic", "PANIC", []string{"PANIC"}, true},
	{"Alert", "ALERT", []string{"ALERT"}, true},
	{"Severe", "SEVERE", []string{"SEVERE"}, true},
	{"Critical", "CRIT", []string{"CRIT", "CRITICAL"}, true},
	{"Emergency", "EMERG", []string{"EMERG", "EMERGENCY"}, true},
	{"Exception", "EXCEPTION", []string{"EXCEPTION"}, true},
	{"Crash", "CRASH", []string{"CRASH", "CRASHED"}, true},
	{"Failure", "FAILURE", []string{"FAILED", "FAILURE"}, true},
	{"Deadlock", "DEADLOCK", []string{"DEADLOCK"}, true},
	{"Timeout", "TIMEOUT", []string{"TIMEOUT"}, true},
}

var charTokens = []charToken{
	{"Colon", ':'}, {"Semicolon", ';'}, {"Dash", '-'}, {"Underscore", '_'},
	{"Fslash", '/'}, {"Bslash", '\\'}, {"Period", '.'}, {"Comma", ','},
	{"Singlequote", '\''}, {"Doublequote", '"'}, {"Backtick", '`'}, {"Tilda", '~'},
	{"Star", '*'}, {"Plus", '+'}, {"Equal", '='}, {"Parenopen", '('},
	{"Parenclose", ')'}, {"Braceopen", '{'}, {"Braceclose", '}'}, {"Bracketopen", '['},
	{"Bracketclose", ']'}, {"Ampersand", '&'}, {"Exclamation", '!'}, {"At", '@'},
	{"Pound", '#'}, {"Dollar", '$'}, {"Percent", '%'}, {"Uparrow", '^'},
}

// maxKeyword is the longest keyword length the SWAR matcher supports. The fold
// expressions below cover 1..9; adding a longer keyword requires extending them.
const maxKeyword = 9

func main() {
	maxLen := 0
	for _, kt := range keywordTokens {
		for _, kw := range kt.Keywords {
			if len(kw) > maxLen {
				maxLen = len(kw)
			}
			if len(kw) < 1 || len(kw) > maxKeyword {
				log.Fatalf("keyword %q length %d out of supported range 1..%d", kw, len(kw), maxKeyword)
			}
		}
	}

	var b strings.Builder
	b.WriteString(header)
	fmt.Fprintf(&b, "\n// maxSpecialTokenLen is the longest keyword eligible for special-token promotion.\nconst maxSpecialTokenLen = %d\n", maxLen)
	genGetSpecialToken(&b, maxLen)
	genTokenToString(&b)
	genIsImportant(&b)
	genAddSpecialCharTokens(&b)

	src, err := format.Source([]byte(b.String()))
	if err != nil {
		log.Fatalf("format generated source: %v\n----\n%s", err, b.String())
	}
	// Output path defaults to the in-package file; the up-to-date test passes a
	// temp path to diff against it.
	out := "token_tables_gen.go"
	if len(os.Args) > 1 {
		out = os.Args[1]
	}
	if err := os.WriteFile(out, src, 0644); err != nil {
		log.Fatal(err)
	}
}

const header = `// Unless explicitly stated otherwise all files in this repository are licensed
// under the Apache License Version 2.0.
// This product includes software developed at Datadog (https://www.datadoghq.com/).
// Copyright 2016-present Datadog, Inc.

// Code generated by gen_token_tables.go; DO NOT EDIT.

package preprocessor

import (
	"encoding/binary"
	"strings"
)
`

// packConst packs the first n bytes of kw (uppercased) little-endian into a
// readable OR-expression of character literals, e.g. 'J'|'A'<<8|'N'<<16.
func packConst(kw string, n int) string {
	parts := make([]string, 0, n)
	for i := range n {
		lit := strconv.QuoteRune(rune(upper(kw[i])))
		if i == 0 {
			parts = append(parts, lit)
		} else {
			parts = append(parts, fmt.Sprintf("%s<<%d", lit, 8*i))
		}
	}
	return strings.Join(parts, "|")
}

func upper(c byte) byte {
	if c >= 'a' && c <= 'z' {
		return c - 32
	}
	return c
}

// foldExpr returns the `folded := ...` statement that packs the first min(L,8)
// case-folded bytes of input into a comparison key, matching packConst.
func foldExpr(L int) string {
	switch L {
	case 1:
		return "folded := input[0] &^ asciiCaseBit"
	case 2:
		return "folded := uint64(binary.LittleEndian.Uint16(input) & asciiUpperMask16)"
	case 3:
		return "folded := uint64(binary.LittleEndian.Uint16(input)&asciiUpperMask16) | uint64(input[2]&^asciiCaseBit)<<16"
	case 4:
		return "folded := uint64(binary.LittleEndian.Uint32(input) & asciiUpperMask32)"
	case 5:
		return "folded := uint64(binary.LittleEndian.Uint32(input)&asciiUpperMask32) | uint64(input[4]&^asciiCaseBit)<<32"
	case 6:
		return "folded := uint64(binary.LittleEndian.Uint32(input)&asciiUpperMask32) | uint64(binary.LittleEndian.Uint16(input[4:])&asciiUpperMask16)<<32"
	case 7:
		return "folded := uint64(binary.LittleEndian.Uint32(input)&asciiUpperMask32) | uint64(binary.LittleEndian.Uint16(input[4:])&asciiUpperMask16)<<32 | uint64(input[6]&^asciiCaseBit)<<48"
	case 8, 9:
		return "folded := binary.LittleEndian.Uint64(input) & asciiUpperMask64"
	}
	log.Fatalf("no fold expression for length %d", L)
	return ""
}

func genGetSpecialToken(b *strings.Builder, maxLen int) {
	b.WriteString(`
// getSpecialToken returns a case-insensitive special token, or End if the run is
// not a recognized keyword. It matches a machine word at a time (SWAR):
// binary.LittleEndian loads the bytes and an asciiCaseBit mask folds case,
// avoiding a scratch buffer or string allocation.
func getSpecialToken(input []byte) Token {
	switch len(input) {
`)
	for L := 1; L <= maxLen; L++ {
		// Collect, in master order, the keywords of this length grouped by token.
		type arm struct {
			consts []string // packed constants (or first-8 for L==9)
			tails  []byte   // 9th byte for L==9, parallel to consts
			ret    string
		}
		var arms []arm
		for _, kt := range keywordTokens {
			var a arm
			a.ret = kt.Const
			for _, kw := range kt.Keywords {
				if len(kw) != L {
					continue
				}
				if L == maxKeyword {
					a.consts = append(a.consts, packConst(kw, 8))
					a.tails = append(a.tails, upper(kw[8]))
				} else {
					a.consts = append(a.consts, packConst(kw, L))
				}
			}
			if len(a.consts) > 0 {
				arms = append(arms, a)
			}
		}
		if len(arms) == 0 {
			continue
		}

		fmt.Fprintf(b, "case %d:\n%s\n", L, foldExpr(L))
		b.WriteString("switch folded {\n")
		for _, a := range arms {
			if L == maxKeyword {
				// One arm per keyword: the 9th byte disambiguates.
				for i, c := range a.consts {
					fmt.Fprintf(b, "case %s:\nif input[8]&^asciiCaseBit == %s {\nreturn %s\n}\n",
						c, strconv.QuoteRune(rune(a.tails[i])), a.ret)
				}
			} else {
				fmt.Fprintf(b, "case %s:\nreturn %s\n", strings.Join(a.consts, ", "), a.ret)
			}
		}
		b.WriteString("}\n")
	}
	b.WriteString("}\nreturn End\n}\n")
}

func genTokenToString(b *strings.Builder) {
	b.WriteString(`
// tokenToString converts a single token to a debug string.
func tokenToString(token Token) string {
	if token >= D1 && token <= D10 {
		return strings.Repeat("D", int(token-D1)+1)
	} else if token >= C1 && token <= C10 {
		return strings.Repeat("C", int(token-C1)+1)
	}
	switch token {
	case Space:
		return " "
`)
	for _, ct := range charTokens {
		fmt.Fprintf(b, "case %s:\nreturn %s\n", ct.Const, strconv.Quote(string(ct.Char)))
	}
	for _, kt := range keywordTokens {
		fmt.Fprintf(b, "case %s:\nreturn %s\n", kt.Const, strconv.Quote(kt.Debug))
	}
	b.WriteString("}\nreturn \"\"\n}\n")
}

func genIsImportant(b *strings.Builder) {
	var crit []string
	for _, kt := range keywordTokens {
		if kt.Critical {
			crit = append(crit, kt.Const)
		}
	}
	b.WriteString(`
// isImportant reports whether any token is a critical-severity keyword; such
// logs bypass adaptive sampling.
func isImportant(tokens []Token) bool {
	for _, t := range tokens {
		switch t {
`)
	fmt.Fprintf(b, "case %s:\nreturn true\n", strings.Join(crit, ", "))
	b.WriteString("}\n}\nreturn false\n}\n")
}

func genAddSpecialCharTokens(b *strings.Builder) {
	b.WriteString(`
// addSpecialCharTokens sets the single-byte special-character tokens in the
// classification lookup table.
func addSpecialCharTokens(lookup *[256]Token) {
`)
	for _, ct := range charTokens {
		fmt.Fprintf(b, "lookup[%s] = %s\n", strconv.QuoteRune(rune(ct.Char)), ct.Const)
	}
	b.WriteString("}\n")
}
